from steambench_harness.rng import Mulberry32

# Ground-truth vectors generated by the canonical JS mulberry32 for seed=42
# (see /tmp/mb.mjs in the build log). If these ever fail, the Python and TS
# implementations have diverged and replay-verification across languages breaks.
JS_U32_SEED42 = [
    2581720956, 1925393290, 3661312704, 2876485805,
    750819978, 2261697747, 1173505300, 2683257857,
]
JS_FLOAT_SEED42 = [
    0.6011037519201636, 0.44829055899754167, 0.8524657934904099,
    0.6697340414393693, 0.17481389874592423, 0.5265925421845168,
    0.2732279943302274, 0.6247446539346129,
]


def test_matches_js_uint32():
    r = Mulberry32(42)
    assert [r.next_u32() for _ in range(8)] == JS_U32_SEED42


def test_matches_js_float():
    r = Mulberry32(42)
    got = [r.random() for _ in range(8)]
    assert got == JS_FLOAT_SEED42


def test_deterministic_per_seed():
    a = [Mulberry32(7).random() for _ in range(5)]
    b = [Mulberry32(7).random() for _ in range(5)]
    assert a == b


def test_choice_and_randrange_bounds():
    r = Mulberry32(1)
    for _ in range(1000):
        assert 0 <= r.randrange(13) < 13
    assert r.choice(["x"]) == "x"
